import boto3
from botocore.exceptions import NoCredentialsError, PartialCredentialsError
import logging

# Initialize Boto3 clients and resources
s3 = boto3.client('s3')
sns = boto3.client('sns')
logger = logging.getLogger()
logger.setLevel(logging.INFO)

def lambda_handler(event, context):
    # Extract bucket name and key from the event
    bucket_name = event['Records'][0]['s3']['bucket']['name']
    object_key = event['Records'][0]['s3']['object']['key']
    
    try:
        # Read image data from S3
        response = s3.get_object(Bucket=bucket_name, Key=object_key)
        image_data = response['Body'].read()
        
        # Process the image (example: increase brightness)
        processed_image_data = process_image(image_data)  # You need to implement this function
        
        # Write processed image data back to S3
        new_object_key = f"processed_{object_key}"
        s3.put_object(Bucket=bucket_name, Key=new_object_key, Body=processed_image_data)
        
        # Log the successful processing
        logger.info(f"Processed {new_object_key}")
        
        # Send notification via SNS
        sns.publish(
            TopicArn='your-sns-topic-arn',
            Message=f"Image processed: {new_object_key}"
        )
        
        return {
            'statusCode': 200,
            'body': f'Processed image saved as {new_object_key}'
        }
    
    except (NoCredentialsError, PartialCredentialsError) as e:
        logger.error(f"Credential error: {e}")
        return {
            'statusCode': 500,
            'body': 'Failed to process image due to credential issues'
        }
    except Exception as e:
        logger.error(f"Error processing image: {e}")
        return {
            'statusCode': 500,
            'body': f'Failed to process image: {str(e)}'
        }

def process_image(image_data):
    # Placeholder function for image processing
    return image_data

